import sys

def main():
    N, S, M, L = map(int, sys.stdin.read().split())
    min_cost = float('inf')

    # Try all combinations of 6, 8, 12 packs
    for a in range(0, N // 6 + 2):  # +2 to allow over-purchasing
        for b in range(0, N // 8 + 2):
            for c in range(0, N // 12 + 2):
                total_eggs = a * 6 + b * 8 + c * 12
                if total_eggs >= N:
                    cost = a * S + b * M + c * L
                    if cost < min_cost:
                        min_cost = cost

    print(min_cost)

if __name__ == "__main__":
    main()
